'use client';

import React, { useState, useEffect } from 'react';
import Link from 'next/link';
import { z } from 'zod';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { useRouter } from 'next/navigation';
import { fetchSignInMethodsForEmail } from 'firebase/auth';
import { Loader2 } from 'lucide-react';

import { Icons } from '@/components/icons';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import { Form, FormControl, FormField, FormItem, FormLabel, FormMessage } from '@/components/ui/form';
import { useToast } from '@/hooks/use-toast';
import { countries } from '@/lib/countries';
import { useAuth } from '@/firebase';
import { sendOtpEmail } from '@/app/actions/email';

const passwordValidation = new RegExp(/^(?=.*[a-z])(?=.*[A-Z])(?=.*\d)[a-zA-Z\d]{8,}$/);

const formSchema = z
  .object({
    username: z.string().min(3, 'Username must be at least 3 characters.'),
    email: z.string().email({ message: 'Please enter a valid email address.' }),
    password: z.string().regex(passwordValidation, {
      message:
        'Password must be at least 8 characters long and contain at least one uppercase letter, one lowercase letter, and one number.',
    }),
    confirmPassword: z.string(),
    country: z.string().min(1, 'Please select a country.'),
  })
  .refine((data) => data.password === data.confirmPassword, {
    message: "Passwords don't match",
    path: ['confirmPassword'],
  });

export default function RegisterPage() {
  const { toast } = useToast();
  const router = useRouter();
  const auth = useAuth();
  const [currency, setCurrency] = useState<string>('');
  const [isLoading, setIsLoading] = useState(false);

  const form = useForm<z.infer<typeof formSchema>>({
    resolver: zodResolver(formSchema),
    defaultValues: {
      username: '',
      email: '',
      password: '',
      confirmPassword: '',
      country: '',
    },
  });

  const selectedCountryCode = form.watch('country');

  useEffect(() => {
    if (selectedCountryCode) {
      const country = countries.find((c) => c.code === selectedCountryCode);
      setCurrency(country?.currency.symbol || '');
    } else {
      setCurrency('');
    }
  }, [selectedCountryCode]);

  const onSubmit = async (values: z.infer<typeof formSchema>) => {
    setIsLoading(true);
    try {
      const signInMethods = await fetchSignInMethodsForEmail(auth, values.email);
      if (signInMethods.length > 0) {
        form.setError('email', {
          type: 'manual',
          message: 'This email address is already in use.',
        });
        setIsLoading(false);
        return;
      }

      const otp = Math.floor(100000 + Math.random() * 900000).toString();
      sessionStorage.setItem('registrationData', JSON.stringify(values));
      sessionStorage.setItem('otp', otp);

      const result = await sendOtpEmail(values.email, otp);

      if (result.success) {
        toast({
          title: 'Verification Code Sent',
          description: `A 6-digit code has been sent to ${values.email}.`,
        });
        router.push(`/otp-verification?email=${encodeURIComponent(values.email)}`);
      } else {
        let errorMessage = result.error || 'Failed to send verification email.';
        
        if (errorMessage.includes('EAUTH')) {
          errorMessage = 'SMTP Auth Failed: If using Gmail, please use an App Password instead of your login password.';
        } else if (errorMessage.includes('EBADNAME') || errorMessage.includes('ENOTFOUND')) {
          errorMessage = 'Invalid SMTP Host: Please ensure SMTP_HOST in .env is a server like smtp.gmail.com and not an email address.';
        }
        
        throw new Error(errorMessage);
      }
    } catch (error: any) {
      console.error('Registration flow error:', error);
      toast({
        variant: 'destructive',
        title: 'Registration Error',
        description: error.message || 'An unexpected error occurred.',
      });
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="flex min-h-screen items-center justify-center bg-muted/30 p-4">
      <div className="w-full max-w-md space-y-6 rounded-2xl bg-card p-8 text-card-foreground shadow-lg">
        <div className="flex flex-col items-center justify-center text-center">
          <div className="flex items-center gap-3 mb-2">
            <Icons.Logo className="h-12 w-12" />
            <span className="text-4xl font-bold bg-gradient-to-tr from-primary to-accent bg-clip-text text-transparent tracking-tight">
              Wallet Tally
            </span>
          </div>
          <p className="text-muted-foreground">Join Wallet Tally and start managing your finances</p>
        </div>

        <Form {...form}>
          <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-4">
            <FormField
              control={form.control}
              name="username"
              render={({ field }) => (
                <FormItem>
                  <FormLabel>Username</FormLabel>
                  <FormControl>
                    <Input placeholder="e.g. johndoe" {...field} disabled={isLoading} />
                  </FormControl>
                  <FormMessage />
                </FormItem>
              )}
            />
            <FormField
              control={form.control}
              name="email"
              render={({ field }) => (
                <FormItem>
                  <FormLabel>Email</FormLabel>
                  <FormControl>
                    <Input type="email" placeholder="e.g. johndoe@example.com" {...field} disabled={isLoading} />
                  </FormControl>
                  <FormMessage />
                </FormItem>
              )}
            />
            <FormField
              control={form.control}
              name="password"
              render={({ field }) => (
                <FormItem>
                  <FormLabel>Password</FormLabel>
                  <FormControl>
                    <Input type="password" placeholder="********" {...field} disabled={isLoading} />
                  </FormControl>
                  <FormMessage />
                </FormItem>
              )}
            />
            <FormField
              control={form.control}
              name="confirmPassword"
              render={({ field }) => (
                <FormItem>
                  <FormLabel>Confirm Password</FormLabel>
                  <FormControl>
                    <Input type="password" placeholder="********" {...field} disabled={isLoading} />
                  </FormControl>
                  <FormMessage />
                </FormItem>
              )}
            />
            <FormField
              control={form.control}
              name="country"
              render={({ field }) => (
                <FormItem>
                  <FormLabel>Country</FormLabel>
                  <Select onValueChange={field.onChange} defaultValue={field.value} disabled={isLoading}>
                    <FormControl>
                      <SelectTrigger>
                        <SelectValue placeholder="Select your country" />
                      </SelectTrigger>
                    </FormControl>
                    <SelectContent>
                      {countries.map((country) => (
                        <SelectItem key={country.code} value={country.code}>
                          {country.name}
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                  <FormMessage />
                </FormItem>
              )}
            />
            <div className="space-y-2">
              <Label>Currency</Label>
              <Input
                value={currency}
                readOnly
                placeholder="Currency symbol"
                className="bg-muted"
              />
            </div>
            <Button
              type="submit"
              disabled={isLoading}
              className="w-full bg-gradient-to-tr from-primary to-accent text-white hover:opacity-90"
            >
              {isLoading ? (
                <>
                  <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                  Sending Code...
                </>
              ) : (
                'Register'
              )}
            </Button>
          </form>
        </Form>

        <div className="text-center text-sm text-muted-foreground pt-4 border-t">
          <p>
            Already have an account?{' '}
            <Link href="/login" className="font-medium text-primary hover:underline">
              Login here
            </Link>
          </p>
        </div>
      </div>
    </div>
  );
}
